void CaseSameColumnNameAndSameControlNameHandle(string ColumnName)
{
    if (ListOfColunmData != null)
    {
        byte Count = (byte)ListOfColunmData.Count(x => x.Name == ColumnName);

        if (Count > 1)
        {
            short Index = (short)ListOfColunmData.FindLastIndex(x => x.Name == ColumnName);

            ListOfColunmData[Index].Name = ListOfColunmData[Index].Name + 2;
        }
    }
}

List<string> GetListOfInitializedProperties()
{
    List<string> ListOfInitializedProperties = new List<string>();

    enControls ControlName = enControls.None;

    Point LabelPoint = new Point(0, 10);
    Point ControlPoint = new Point(210, 10);

    for (short i = 0; i < ListOfColunmData.Count; i++)
    {
        if (ListOfColunmData[i].Generate)
        {
            Enum.TryParse(ListOfColunmData[i].ControlName, out ControlName);

            if (ControlName != enControls.CheckBox)
            {
                ListOfInitializedProperties.Add(GetInitializedProperties(enControls.Label, ListOfColunmData[i].Name, i, ListOfColunmData[i].IsNullable, LabelPoint, true));
                
                ListOfInitializedProperties.Add(GetInitializedProperties(ControlName, ListOfColunmData[i].Name, i, ListOfColunmData[i].IsNullable, ControlPoint));
            }
            else
            {
                ListOfInitializedProperties.Add(GetInitializedProperties(ControlName, ListOfColunmData[i].Name, i, ListOfColunmData[i].IsNullable, ControlPoint));
            }

            if (ControlPoint.Y >= 425)
            {
                ControlPoint.Y = 10;
                ControlPoint.X += 440;

                LabelPoint.Y = 10;
                LabelPoint.X += 440;
            }
            else
            {
                ControlPoint.Y += 35;
                LabelPoint.Y += 35;
            }
        }
    }

    return ListOfInitializedProperties;
}

public static string GetControlName(enControls ControlName, string ColumnName, bool IsLabel = false)
        {
            switch (ControlName)
            {
                case enControls.Label:
                    if (!IsLabel)
                    {
                        return $"lb{ColumnName}Result";
                    }
                    else
                    {
                        return $"lb{ColumnName}";
                    }
                case enControls.CheckBox:
                    return $"chb{ColumnName}";
                case enControls.TextBox:
                    return $"txtb{ColumnName}";
                case enControls.MaskedTextBox:
                    return $"mtxtb{ColumnName}";
                case enControls.DateTimePicker:
                    return $"dtp{ColumnName}";
                case enControls.ComboBox:
                    return $"cb{ColumnName}";
                default:
                    return $"lb{ColumnName}";
            }
        }

