string RemoveAnyDigitsInString(string Value)
{
    for (short i = 0; i < Value.Length; i++)
    {
        if (char.IsDigit(Value[i]))
        {
            Value = Value.Replace(Value[i].ToString(), "");
        }
    }
    
    return Value;
}


